import { UploadFile } from '@mui/icons-material';
import { Box, Button, Card, Stack, Typography } from '@mui/material';
import _ from 'lodash';
import type { FC } from 'react';
import type { DropTargetMonitor } from 'react-dnd';
import { useDrop } from 'react-dnd';
import { NativeTypes } from 'react-dnd-html5-backend';

import { translate } from '@/utils/i18n';

export interface DndBoxProps {
  onDrop: (files: File[]) => void;
}

const allowedExtensions = ['.mp4', '.MP4', '.mov', '.MOV'];

export const DndBox: FC<DndBoxProps> = ({ onDrop }) => {
  const [{ canDrop, isOver }, drop] = useDrop(
    () => ({
      accept: [NativeTypes.FILE],
      drop(item: { files: File[] }) {
        onDrop(filterOutUnsupportedFiles(item.files));
      },
      canDrop(item: any) {
        return true;
      },
      hover(item: any) {
        //
      },
      collect: (monitor: DropTargetMonitor) => {
        const item = monitor.getItem() as any;
        if (item) {
          //
        }

        return {
          isOver: monitor.isOver(),
          canDrop: monitor.canDrop(),
        };
      },
    }),
    [onDrop],
  );

  const filterOutUnsupportedFiles = (files: Iterable<File>) => {
    return [...files].filter((file) =>
      allowedExtensions.find((ext) => file.name.endsWith(ext)),
    );
  };

  const isActive = canDrop && isOver;
  return (
    <Box
      ref={drop as any}
      sx={{
        // https://kovart.github.io/dashed-border-generator/
        backgroundImage:
          `url("data:image/svg+xml,%3csvg width='100%25' height='100%25' ` +
          `xmlns='http://www.w3.org/2000/svg'%3e%3crect width='100%25' height='100%25' ` +
          `fill='none' stroke='lightgray' stroke-width='4' stroke-dasharray='2%2c 8' ` +
          `stroke-dashoffset='0' stroke-linecap='square'/%3e%3c/svg%3e")`,
        textAlign: 'center',
        p: '1px',
      }}
    >
      <Button
        color="neutral"
        component="label"
        fullWidth
        role={undefined}
        sx={{ p: 4 }}
        tabIndex={-1}
        variant="contained"
      >
        <Stack direction="column" textAlign="center" spacing={1}>
          <Box>
            <UploadFile color="primary" fontSize="large" />
          </Box>
          <Typography variant="inherit">
            {isActive
              ? translate('release_to_drop')
              : translate('click_to_upload_or_drag_and_drop')}
          </Typography>
          <Typography color="neutral" variant="body2">
            MOV or MP4
          </Typography>
        </Stack>
        <input
          accept={allowedExtensions.join(',')}
          hidden
          multiple
          type="file"
          onChange={(e) => {
            const files = e.target.files ?? [];
            onDrop(filterOutUnsupportedFiles(files));
          }}
        />
      </Button>
    </Box>
  );
};

